#pragma once

#include "common.h"
#include "core.h"
#include "shared.h"
#include "instruction.h"
#include "state.h"

namespace via
{

// Machine code executable type
using viaMCodeExec_t = int (*)(viaState *);

// Logically bound chunk of instructions
// Generated by the compiler
struct viaChunk
{
    // Bytecode of the chunk
    viaInstruction *bytecode = nullptr;
    // The amount of instructions that the bytecode of the chunk contains
    size_t len = 0;
    // Pointer to the machine code of the chunk, function pointer
    viaMCodeExec_t mcode = nullptr;
};

} // namespace via